+
+        let rows = conn
+            .query("SELECT COALESCE(MAX(val), 0) FROM empty_tbl;")
+            .unwrap();
+        assert_eq!(rows.len(), 1);
+        assert_eq!(rows[0].values()[0], SqliteValue::Integer(0));
